var e=[{id:`L6_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_AP_NULL`,text:{KOREA:`크윽……!`,JPN:`くっ……！`,ENG:`Kuh...!`,TWN:`呃……！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`KYLE_DELTA_AP_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`KYLE_DELTA_AP_NULL`,text:{KOREA:`시영 씨! 시영 씨! 정신 차려요!!`,JPN:`シノンさん！　シノンさん！　しっかりしてください！`,ENG:`Shiyoung! Shiyoung! Wake up!!`,TWN:`時雨！！時雨！！振作一點！！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`KYLE_DELTA_AP_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`KYLE_DELTA_AP_NULL`,text:{KOREA:`이, 이런……!`,JPN:`そ、そんな……！`,ENG:`Oh, no...!`,TWN:`這，這……該死！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`KYLE_DELTA_AP_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`CYBERCAT_DELTA_NULL_NULL`,text:{KOREA:`소령! 내 말 들려 소령!`,JPN:`少佐！　聞こえる？　少佐！`,ENG:`Major! Can you hear me, Major?!`,TWN:`少校！能聽見我說話嗎，少校！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`CYBERCAT_DELTA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`CYBERCAT_DELTA_NULL_NULL`,text:{KOREA:`엔진이 당했어!`,JPN:`エンジンがやられたわ！`,ENG:`Engine's shot!`,TWN:`引擎被擊中了！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`CYBERCAT_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`CYBERCAT_DELTA_NULL_NULL`,text:{KOREA:`이대로 함선이 추락하는 건 시간 문제야!`,JPN:`このままじゃ艦船が墜落するのも時間の問題よ！`,ENG:`It's only a matter of time before the ship goes down!`,TWN:`這樣下去，艦船墜落只是時間問題！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`CYBERCAT_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`KYLE_DELTA_AP_NULL`,text:{KOREA:`미안해요, 사이버캣. 네피림을 선체 밖으로 떨어트리지 못했어요.`,JPN:`ごめんなさい、サイバーキャット。ネフィリムを船外に振り落とせませんでした。`,ENG:`I'm sorry, Cyber Cat. We couldn't throw the Nephil off the ship.`,TWN:`抱歉，賽博貓。我沒能把船身外的諾菲力擊落。`},stage:{bg:`CORRIDOR`,slots:{L:{char_id:`CYBERCAT_DELTA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`KYLE_DELTA_AP_NULL`,face:`UNIT_DESPAIR`}}}},{id:`L18_1`,type:`dialog`,speaker:`CYBERCAT_DELTA_NULL_NULL`,text:{KOREA:`정신 차려, 소령!`,JPN:`しっかりしてよ、少佐！`,ENG:`Snap out of it, Major!`,TWN:`打起精神來，少校！`},stage:{bg:`CORRIDOR`,slots:{L:{char_id:`CYBERCAT_DELTA_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`KYLE_DELTA_AP_NULL`,face:`UNIT_DESPAIR`}}}},{id:`L19_1`,type:`dialog`,speaker:`CYBERCAT_DELTA_NULL_NULL`,text:{KOREA:`사과 같은 건 나중에 하라고! 본 함선은 지금으로부터 1분 뒤에 비상 착륙 절차에 들어갈 거야!`,JPN:`謝罪なら後で聞くわ！　本艦船は今から1分後に非着陸態勢に入る！`,ENG:`You can apologize later! This ship is going into emergency landing mode in 1 minute!`,TWN:`道歉留到以後再說！艦船1分鐘後將會進入緊急迫降狀態！`},stage:{bg:`CORRIDOR`,slots:{L:{char_id:`CYBERCAT_DELTA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`KYLE_DELTA_AP_NULL`,face:`UNIT_DESPAIR`}}}},{id:`L20_1`,type:`dialog`,speaker:`CYBERCAT_DELTA_NULL_NULL`,text:{KOREA:`그러니까 그전에 능구렁이를 데리고 먼저 탈출 포트로 탈출해!`,JPN:`だからその前に、その狸を連れて先に脱出ポートで脱出して！`,ENG:`So get Smirky and go to the escape pod before it does!`,TWN:`所以，在那之前帶上那個老油條，先從逃出艙口逃離吧！`},stage:{bg:`CORRIDOR`,slots:{L:{char_id:`CYBERCAT_DELTA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`KYLE_DELTA_AP_NULL`,face:`UNIT_DESPAIR`}}}},{id:`L22_1`,type:`dialog`,speaker:`KYLE_DELTA_AP_NULL`,text:{KOREA:`그게 무슨?`,JPN:`どういう意味ですか？`,ENG:`What?`,TWN:`你說什麼？`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`KYLE_DELTA_AP_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`KYLE_DELTA_AP_NULL`,text:{KOREA:`사이버캣, 그게 무슨 소리예요! 당신은 어쩌려고요!`,JPN:`サイバーキャット、それはどういう意味ですか！　あなたはどうするんですか！`,ENG:`Cyber Cat, what are you talking about? What about you?!`,TWN:`賽博貓，這是什麼意思！那你怎麼辦！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`KYLE_DELTA_AP_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L24_1`,type:`dialog`,speaker:`CYBERCAT_DELTA_NULL_NULL`,text:{KOREA:`어쩌긴! 뭘 어째!`,JPN:`どうって！　そんなの決まってるでしょ！`,ENG:`What about me? You know what!`,TWN:`什麼怎麼辦！還能怎麼辦！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`CYBERCAT_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`CYBERCAT_DELTA_NULL_NULL`,text:{KOREA:`당연히 저 아종 네피림을 방위선에서 최대한 먼 곳에 떨어트려 놔야지!`,JPN:`あの亜種ネフィリムを防衛線からできるだけ遠く離れた場所に落としに行くのよ！`,ENG:`I have to take that Nephil subspecies as far away from the Defense Line as possible!`,TWN:`當然是將那隻亞種諾菲力帶離防線越遠越好！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`CYBERCAT_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L28_1`,type:`dialog`,speaker:`KYLE_DELTA_AP_NULL`,text:{KOREA:`그, 그건 제가 할게요!`,JPN:`そ、それは、私がやります！`,ENG:`I-I'll do that!`,TWN:`那，那讓我來！`},stage:{bg:`CORRIDOR`,slots:{L:{char_id:`CYBERCAT_DELTA_NULL_NULL`,face:`UNIT_HATE`},C:null,R:{char_id:`KYLE_DELTA_AP_NULL`,face:`UNIT_IDLE`}}}}];export{e as default};